import React, { useState } from "react";
import { useDoctors } from "../hooks";
import Modal from "../components/Modal";
import Spinner from "../components/Spinner";
import Toast from "../components/Toast";

const inputStyle = {
  background: "#020810",
  border: "1px solid #0d3a5c",
  borderRadius: 8,
  padding: "10px 14px",
  color: "#cfd8dc",
  fontFamily: "'DM Mono', monospace",
  fontSize: 14,
  outline: "none",
  width: "100%",
  boxSizing: "border-box",
};
const labelStyle = { display: "block", color: "#546e7a", fontFamily: "'DM Mono', monospace", fontSize: 11, letterSpacing: 1, textTransform: "uppercase", marginBottom: 6 };
const errorStyle = { color: "#ff4d6d", fontSize: 12, marginTop: 4, fontFamily: "'DM Mono', monospace" };

const EMPTY_FORM = { name: "", specialization: "", start_hour: "", end_hour: "" };

export default function DoctorsPage() {
  const { doctors, loading, error, addDoctor } = useDoctors();
  const [search, setSearch] = useState("");
  const [modalOpen, setModalOpen] = useState(false);
  const [form, setForm] = useState(EMPTY_FORM);
  const [formErrors, setFormErrors] = useState({});
  const [submitting, setSubmitting] = useState(false);
  const [toast, setToast] = useState(null);

  const filtered = doctors.filter(
    (d) =>
      d.name.toLowerCase().includes(search.toLowerCase()) ||
      d.specialization.toLowerCase().includes(search.toLowerCase())
  );

  const validate = () => {
    const errs = {};
    if (!form.name || form.name.trim().length < 3) errs.name = "Name must be at least 3 characters";
    if (!form.specialization) errs.specialization = "Specialization is required";
    const s = parseInt(form.start_hour, 10);
    const e = parseInt(form.end_hour, 10);
    if (isNaN(s) || s < 0 || s > 23) errs.start_hour = "Must be 0–23";
    if (isNaN(e) || e < 0 || e > 23) errs.end_hour = "Must be 0–23";
    if (!errs.start_hour && !errs.end_hour && s >= e) errs.end_hour = "End hour must be greater than start hour";
    return errs;
  };

  const handleSubmit = async () => {
    const errs = validate();
    setFormErrors(errs);
    if (Object.keys(errs).length > 0) return;
    setSubmitting(true);
    try {
      await addDoctor({
        name: form.name.trim(),
        specialization: form.specialization.trim(),
        start_hour: parseInt(form.start_hour, 10),
        end_hour: parseInt(form.end_hour, 10),
      });
      setForm(EMPTY_FORM);
      setFormErrors({});
      setModalOpen(false);
      setToast({ message: `${form.name} added successfully!`, type: "success" });
    } catch (e) {
      setFormErrors({ api: e.response?.data?.detail || "Failed to add doctor" });
    } finally {
      setSubmitting(false);
    }
  };

  const specColors = {
    Cardiology: "#ff4d6d",
    Neurology: "#7c4dff",
    Orthopedics: "#00e5b0",
    Dermatology: "#ffb74d",
    "General Practice": "#00bcd4",
  };

  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 32 }}>
        <div>
          <h1 style={{ fontFamily: "'Syne', sans-serif", fontSize: 32, color: "#e0f7fa", margin: 0 }}>Doctors</h1>
          <p style={{ color: "#546e7a", fontFamily: "'DM Mono', monospace", marginTop: 6 }}>
            {doctors.length} registered physicians
          </p>
        </div>
        <button
          onClick={() => setModalOpen(true)}
          style={{
            background: "linear-gradient(135deg, #006080, #00bcd4)",
            border: "none", borderRadius: 9, padding: "11px 22px",
            color: "#fff", fontFamily: "'Syne', sans-serif", fontWeight: 700,
            fontSize: 14, cursor: "pointer",
          }}
        >
          + Add Doctor
        </button>
      </div>

      {/* Search */}
      <div style={{ marginBottom: 28 }}>
        <input
          style={{ ...inputStyle, maxWidth: 360 }}
          placeholder="Search by name or specialization…"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      {loading && <div style={{ textAlign: "center", padding: 40 }}><Spinner /></div>}
      {error && <p style={{ color: "#ff4d6d", fontFamily: "'DM Mono', monospace" }}>{error}</p>}

      {/* Grid */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: 18 }}>
        {filtered.map((d) => {
          const accentColor = specColors[d.specialization] || "#00bcd4";
          return (
            <div key={d.id} style={{
              background: "#060f1a",
              border: "1px solid #0d3a5c",
              borderTop: `3px solid ${accentColor}`,
              borderRadius: 12,
              padding: "22px 22px 18px",
              transition: "transform 0.15s, box-shadow 0.15s",
            }}
              onMouseEnter={(e) => { e.currentTarget.style.transform = "translateY(-3px)"; e.currentTarget.style.boxShadow = `0 8px 30px ${accentColor}20`; }}
              onMouseLeave={(e) => { e.currentTarget.style.transform = ""; e.currentTarget.style.boxShadow = ""; }}
            >
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
                <h3 style={{ fontFamily: "'Syne', sans-serif", color: "#e0f7fa", fontSize: 17, margin: 0, flex: 1 }}>
                  {d.name}
                </h3>
              </div>
              <span style={{
                display: "inline-block", background: `${accentColor}22`, color: accentColor,
                borderRadius: 6, padding: "3px 10px", fontFamily: "'DM Mono', monospace", fontSize: 11, marginBottom: 14,
              }}>
                {d.specialization}
              </span>
              <div style={{ color: "#546e7a", fontFamily: "'DM Mono', monospace", fontSize: 12 }}>
                🕐 {d.start_hour}:00 – {d.end_hour}:00
              </div>
            </div>
          );
        })}
        {!loading && filtered.length === 0 && (
          <p style={{ color: "#263238", fontFamily: "'DM Mono', monospace", gridColumn: "1/-1", textAlign: "center", padding: 40 }}>
            No doctors found.
          </p>
        )}
      </div>

      {/* Add Doctor Modal */}
      <Modal isOpen={modalOpen} onClose={() => { setModalOpen(false); setForm(EMPTY_FORM); setFormErrors({}); }} title="Add New Doctor">
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          <div>
            <label style={labelStyle}>Full Name</label>
            <input style={inputStyle} placeholder="Dr. Jane Smith" value={form.name}
              onChange={(e) => setForm((f) => ({ ...f, name: e.target.value }))} />
            {formErrors.name && <p style={errorStyle}>{formErrors.name}</p>}
          </div>
          <div>
            <label style={labelStyle}>Specialization</label>
            <input style={inputStyle} placeholder="e.g. Cardiology" value={form.specialization}
              onChange={(e) => setForm((f) => ({ ...f, specialization: e.target.value }))} />
            {formErrors.specialization && <p style={errorStyle}>{formErrors.specialization}</p>}
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
            <div>
              <label style={labelStyle}>Start Hour (0–23)</label>
              <input type="number" min={0} max={23} style={inputStyle} placeholder="9" value={form.start_hour}
                onChange={(e) => setForm((f) => ({ ...f, start_hour: e.target.value }))} />
              {formErrors.start_hour && <p style={errorStyle}>{formErrors.start_hour}</p>}
            </div>
            <div>
              <label style={labelStyle}>End Hour (0–23)</label>
              <input type="number" min={0} max={23} style={inputStyle} placeholder="17" value={form.end_hour}
                onChange={(e) => setForm((f) => ({ ...f, end_hour: e.target.value }))} />
              {formErrors.end_hour && <p style={errorStyle}>{formErrors.end_hour}</p>}
            </div>
          </div>
          {formErrors.api && (
            <div style={{ background: "#2e0d0d", border: "1px solid #ff4d6d", borderRadius: 8, padding: "10px 14px" }}>
              <p style={{ ...errorStyle, margin: 0 }}>{formErrors.api}</p>
            </div>
          )}
          <button
            onClick={handleSubmit}
            disabled={submitting}
            style={{
              marginTop: 4, padding: "12px 0",
              background: submitting ? "#0d3a5c" : "linear-gradient(135deg, #006080, #00bcd4)",
              border: "none", borderRadius: 9, color: "#fff",
              fontFamily: "'Syne', sans-serif", fontSize: 15, fontWeight: 700,
              cursor: submitting ? "not-allowed" : "pointer",
              display: "flex", alignItems: "center", justifyContent: "center", gap: 10,
            }}
          >
            {submitting ? <><Spinner size={18} /> Adding…</> : "Add Doctor"}
          </button>
        </div>
      </Modal>

      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </div>
  );
}
